import{_ as a,C as i,c as o,o as r,j as e,G as n,a2 as s,a as d}from"./chunks/framework.DrNAj9nU.js";const u="/assets/zhengliu-2.CkEDcMI2.png",p="/assets/zhengliu-1.DmSyoOO4.png",q=JSON.parse('{"title":"模型蒸馏（Model Distillation）","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/基础认知/什么是模型蒸馏.md","filePath":"column/AIFuture/基础认知/什么是模型蒸馏.md","lastUpdated":1773825228000}'),c={name:"column/AIFuture/基础认知/什么是模型蒸馏.md"};function h(b,t,g,m,_,f){const l=i("ArticleMetadata");return r(),o("div",null,[t[0]||(t[0]=e("h1",{id:"模型蒸馏-model-distillation",tabindex:"-1"},[d("模型蒸馏（Model Distillation） "),e("a",{class:"header-anchor",href:"#模型蒸馏-model-distillation","aria-label":'Permalink to "模型蒸馏（Model Distillation）"'},"​")],-1)),n(l),t[1]||(t[1]=s('<p><img src="'+u+`" alt="模型蒸馏" loading="lazy"></p><h2 id="一、概念" tabindex="-1">一、概念 <a class="header-anchor" href="#一、概念" aria-label="Permalink to &quot;一、概念&quot;">​</a></h2><p><code>模型蒸馏（Model Distillation）</code>是<strong>机器学习中一种模型压缩和知识迁移的方法</strong>。</p><blockquote><p>核心思想：用一个“大模型”（Teacher，教师模型）训练一个“小模型”（Student，学生模型），让小模型学到大模型的能力。</p></blockquote><p>目的：</p><ol><li><strong>减小模型体积</strong> → 更适合部署在手机、边缘设备、IoT等环境。</li><li><strong>加速推理速度</strong> → 小模型运算快。</li><li><strong>保持性能</strong> → 尽量保留大模型的预测能力或特征表达。</li></ol><p>简单理解：</p><blockquote><p>让“小模型”继承“大模型”的智慧。</p></blockquote><h2 id="二、原理" tabindex="-1">二、原理 <a class="header-anchor" href="#二、原理" aria-label="Permalink to &quot;二、原理&quot;">​</a></h2><p>核心原理是 <strong>知识迁移</strong>，即把大模型学到的“知识”传给小模型。</p><p>具体做法：</p><ol><li><p><strong>大模型预测的概率分布</strong></p><ul><li>Teacher 模型在分类任务中输出 softmax 概率向量。</li><li>不仅告诉你“类别正确”，还告诉你“各类别的相似度”。</li></ul></li><li><p><strong>小模型学习这个概率分布</strong></p><ul><li>Student 模型通过最小化与 Teacher 的预测分布的差异来训练。</li><li>目标函数通常是 <strong>KL散度（KL Divergence）</strong> 或 <strong>交叉熵</strong>。</li></ul></li></ol><p>举个例子：</p><ul><li><p>Teacher 模型对一张图片预测：</p><ul><li>猫：0.7</li><li>狮子：0.2</li><li>狗：0.1</li></ul></li><li><p>Student 模型学习这个分布，而不是只知道“猫是对的”，所以它能捕捉类别之间的细微关系。</p></li></ul><h2 id="三、训练流程" tabindex="-1">三、训练流程 <a class="header-anchor" href="#三、训练流程" aria-label="Permalink to &quot;三、训练流程&quot;">​</a></h2><p>模型蒸馏通常有三种方式：</p><h3 id="_3-1-软标签蒸馏-soft-label-distillation" tabindex="-1">3.1 软标签蒸馏（Soft Label Distillation） <a class="header-anchor" href="#_3-1-软标签蒸馏-soft-label-distillation" aria-label="Permalink to &quot;3.1 软标签蒸馏（Soft Label Distillation）&quot;">​</a></h3><ul><li>直接使用 Teacher 模型输出的概率作为 Student 的训练目标。</li><li>优点：简单、直观。</li></ul><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>流程：</span></span>
<span class="line"><span>Teacher 模型预测 → 生成软标签 → Student 模型学习软标签</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_3-2-特征蒸馏-feature-distillation" tabindex="-1">3.2 特征蒸馏（Feature Distillation） <a class="header-anchor" href="#_3-2-特征蒸馏-feature-distillation" aria-label="Permalink to &quot;3.2 特征蒸馏（Feature Distillation）&quot;">​</a></h3><ul><li>Student 不只学习输出，还学习 Teacher 的中间特征表示（比如隐藏层的向量）。</li><li>优点：保留更多内部结构知识。</li><li>常用于 NLP 或计算机视觉中的大模型压缩。</li></ul><h3 id="_3-3-对抗蒸馏-互信息蒸馏" tabindex="-1">3.3 对抗蒸馏 / 互信息蒸馏 <a class="header-anchor" href="#_3-3-对抗蒸馏-互信息蒸馏" aria-label="Permalink to &quot;3.3 对抗蒸馏 / 互信息蒸馏&quot;">​</a></h3><ul><li>利用对抗训练或信息瓶颈的方法，让 Student 学到 Teacher 更高级的分布特征。</li><li>用于要求高性能的小模型场景。</li></ul><h2 id="四、类比理解" tabindex="-1">四、类比理解 <a class="header-anchor" href="#四、类比理解" aria-label="Permalink to &quot;四、类比理解&quot;">​</a></h2><p>为了更直观地理解，可以用“老师教学生”的比喻：</p><ul><li>Teacher（大模型） = 老师</li><li>Student（小模型） = 学生</li><li>数据 = 教材</li><li>Soft Label / 中间特征 = 老师的讲解和思路</li></ul><p>普通训练：</p><ul><li>学生只看教材自己学 → 很多细节可能学不到</li></ul><p>蒸馏训练：</p><ul><li>学生听老师讲解 → 能快速掌握知识点和思路</li><li>学生体型小、速度快，但能力接近老师</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>解释</th></tr></thead><tbody><tr><td>Teacher</td><td>大模型，知识源</td></tr><tr><td>Student</td><td>小模型，学习目标</td></tr><tr><td>Soft Label</td><td>Teacher 的输出概率，包含丰富信息</td></tr><tr><td>蒸馏目标</td><td>让 Student 学到 Teacher 的能力</td></tr></tbody></table><blockquote><p>模型蒸馏就是把大模型的“智慧”压缩到小模型，让它轻量化且依然强大。</p></blockquote><p><strong>如图所示：</strong><img src="`+p+'" alt="" loading="lazy"></p><p><strong>参考网站：</strong></p><ul><li><a href="https://www.meta-intelligence.tech/insight-distillation?utm_source=chatgpt.com" target="_blank" rel="noreferrer">DeepSeek-R1 模型蒸馏</a></li></ul>',36))])}const S=a(c,[["render",h]]);export{q as __pageData,S as default};
